    /**
     * Constructor with explicit configuration parameters.
     * 
     * @param endpoint OSS endpoint
     * @param accessKeyId Access Key ID
     * @param accessKeySecret Access Key Secret
     * @param bucketName Bucket name
     */
    public OSSService(String endpoint, String accessKeyId, String accessKeySecret, String bucketName) {
        validateParameter("endpoint", endpoint);
        validateParameter("accessKeyId", accessKeyId);
        validateParameter("accessKeySecret", accessKeySecret);
        validateParameter("bucketName", bucketName);

        this.endpoint = endpoint;
        this.accessKeyId = accessKeyId;
        this.accessKeySecret = accessKeySecret;
        this.bucketName = bucketName;
    }

    /**
     * Loads OSS configuration from properties file.
     * 
     * @throws IllegalStateException if configuration cannot be loaded
     */
    private void loadConfiguration() {
        Properties properties = new Properties();
        try (InputStream input = getClass().getClassLoader().getResourceAsStream("oss.properties")) {
            if (input == null) {
                throw new IllegalStateException("Unable to find oss.properties in classpath");
            }
            properties.load(input);

            this.endpoint = properties.getProperty("oss.endpoint");
            this.accessKeyId = properties.getProperty("oss.accessKeyId");
            this.accessKeySecret = properties.getProperty("oss.accessKeySecret");
            this.bucketName = properties.getProperty("oss.bucketName");

            validateParameter("oss.endpoint", this.endpoint);
            validateParameter("oss.accessKeyId", this.accessKeyId);
            validateParameter("oss.accessKeySecret", this.accessKeySecret);
            validateParameter("oss.bucketName", this.bucketName);

        } catch (IOException e) {
            throw new IllegalStateException("Failed to load OSS configuration", e);
        }
    }

    /**
     * Validates that a configuration parameter is not null or empty.
     * 
     * @param paramName parameter name
     * @param paramValue parameter value
     * @throws IllegalStateException if parameter is null or empty
     */
    private void validateParameter(String paramName, String paramValue) {
        if (paramValue == null || paramValue.trim().isEmpty()) {
            throw new IllegalStateException("Configuration parameter '" + paramName + "' is required but not provided");
        }
    }

    /**
     * Uploads a file to Alibaba Cloud OSS.
     * 
     * @param objectName the name of the object in OSS (e.g., "folder/file.jpg")
     * @param data the byte array of file data to upload
     * @return the complete URL to access the uploaded resource
     * @throws IllegalArgumentException if objectName is null/empty or data is null/empty
     * @throws OSSUploadException if upload fails
     */
    public String uploadFile(String objectName, byte[] data) {
        // Validate input parameters
        if (objectName == null || objectName.trim().isEmpty()) {
            throw new IllegalArgumentException("Object name cannot be null or empty");
        }
        if (data == null || data.length == 0) {
            throw new IllegalArgumentException("Data cannot be null or empty");
        }

        OSS ossClient = null;
        ByteArrayInputStream inputStream = null;

        try {
            // Create OSS client instance
            ossClient = new OSSClientBuilder().build(endpoint, accessKeyId, accessKeySecret);

            // Create input stream from byte array
            inputStream = new ByteArrayInputStream(data);

            // Create upload request
            PutObjectRequest putObjectRequest = new PutObjectRequest(bucketName, objectName, inputStream);

            // Execute upload
            PutObjectResult result = ossClient.putObject(putObjectRequest);

            // Construct and return the complete access URL
            String url = buildAccessUrl(objectName);

            return url;

        } catch (OSSException e) {
            // OSS service side exception
            throw new OSSUploadException(
                "OSS service error occurred while uploading file: " + e.getErrorMessage(), 
                e
            );
        } catch (Exception e) {
            // Client side or other exceptions
            throw new OSSUploadException(
                "Failed to upload file to OSS: " + e.getMessage(), 
                e
            );
        } finally {
            // Close input stream
            if (inputStream != null) {
                try {
                    inputStream.close();
                } catch (IOException e) {
                    // Log the exception but don't throw it
                    System.err.println("Failed to close input stream: " + e.getMessage());
                }
            }

            // Shutdown OSS client
            if (ossClient != null) {
                try {
                    ossClient.shutdown();
                } catch (Exception e) {
                    // Log the exception but don't throw it
                    System.err.println("Failed to shutdown OSS client: " + e.getMessage());
                }
            }
        }
    }

    /**
     * Builds the complete access URL for an uploaded object.
     * 
     * @param objectName the name of the object in OSS
     * @return the complete URL
     */
    private String buildAccessUrl(String objectName) {
        // Remove protocol prefix if exists in endpoint
        String cleanEndpoint = endpoint.replaceFirst("^https?://", "");

        // Construct URL: https://bucketName.endpoint/objectName
        StringBuilder urlBuilder = new StringBuilder();
        urlBuilder.append("https://")
                  .append(bucketName)
                  .append(".")
                  .append(cleanEndpoint);

        // Add leading slash if objectName doesn't have one
        if (!objectName.startsWith("/")) {
            urlBuilder.append("/");
        }
        urlBuilder.append(objectName);

        return urlBuilder.toString();
    }

    /**
     * Custom exception for OSS upload operations.
     */
    public static class OSSUploadException extends RuntimeException {
        public OSSUploadException(String message) {
            super(message);
        }

        public OSSUploadException(String message, Throwable cause) {
            super(message, cause);
        }
    }
}
